import type { LLMCallEntity } from '@flusk/entities';

const MODEL_MAX_TOKENS: Record<string, number> = {
  'gpt-4': 8192,
  'gpt-4-turbo': 128000,
  'gpt-4o': 128000,
  'gpt-4o-mini': 128000,
  'gpt-3.5-turbo': 16385,
  'claude-3-opus': 200000,
  'claude-3-sonnet': 200000,
  'claude-3-haiku': 200000,
  'claude-3.5-sonnet': 200000,
  'command-r': 128000,
  'command-r-plus': 128000,
};

const DEFAULT_MAX_TOKENS = 8192;

export interface ContextUtilization {
  callId: string;
  model: string;
  tokensUsed: number;
  maxTokens: number;
  utilization: number;
  underutilized: boolean;
}

export interface ContextUtilizationReport {
  calls: ContextUtilization[];
  underutilizedCount: number;
  avgUtilization: number;
  optimizationOpportunities: ContextUtilization[];
}

const UNDERUTILIZATION_THRESHOLD = 0.10;

export function contextUtilization(
  calls: LLMCallEntity[],
): ContextUtilizationReport {
  const results: ContextUtilization[] = calls.map(c => {
    const t = c.tokens as Record<string, number> | undefined;
    const tokensUsed = (t?.input ?? 0) + (t?.output ?? 0);
    const maxTokens = MODEL_MAX_TOKENS[c.model] ?? DEFAULT_MAX_TOKENS;
    const utilization = maxTokens > 0 ? tokensUsed / maxTokens : 0;
    return {
      callId: c.id,
      model: c.model,
      tokensUsed,
      maxTokens,
      utilization,
      underutilized: utilization < UNDERUTILIZATION_THRESHOLD,
    };
  });

  const underutilized = results.filter(r => r.underutilized);
  const avgUtil = results.length > 0
    ? results.reduce((s, r) => s + r.utilization, 0) / results.length
    : 0;

  return {
    calls: results,
    underutilizedCount: underutilized.length,
    avgUtilization: avgUtil,
    optimizationOpportunities: underutilized,
  };
}
